    },
    {
      "name": "all_placements",
      "input": {
        "submissions": [
          {"id": 1, "status": "placement"},
          {"id": 2, "status": "placement"},
          {"id": 3, "status": "placement"}
        ]
      },
      "output": [
        {"id": 1, "status": "placement"},
        {"id": 2, "status": "placement"},
        {"id": 3, "status": "placement"}
      ],
      "notes": "Check that all placements are displayed when no winners exist."
    },
    {
      "name": "duplicate_submissions",
      "input": {
        "submissions": [
          {"id": 1, "status": "winner"},
